const item = $input.first();
const headers = item.json.headers ?? {};
const signatureHeader = headers['x-hub-signature-256'] ?? headers['X-Hub-Signature-256'] ?? null;
const binaryData = item.binary?.rawBody?.data;
const rawBody = binaryData ? Buffer.from(binaryData, 'base64').toString('utf8') : JSON.stringify(item.json.body ?? item.json);
const appSecret = process.env.WHATSAPP_APP_SECRET || '';
let signatureValid = null;

if (signatureHeader && appSecret) {
  const encoder = new TextEncoder();
  const cryptoKey = await crypto.subtle.importKey('raw', encoder.encode(appSecret), { name: 'HMAC', hash: 'SHA-256' }, false, ['sign']);
  const signatureBuffer = await crypto.subtle.sign('HMAC', cryptoKey, encoder.encode(rawBody));
  const expected = Array.from(new Uint8Array(signatureBuffer)).map((byte) => byte.toString(16).padStart(2, '0')).join('');
  signatureValid = `sha256=${expected}` === signatureHeader;
  if (!signatureValid) {
    return [{ json: { shouldProcess: false, reason: 'invalid_signature', signatureValid } }];
  }
}

let payload;
try {
  payload = JSON.parse(rawBody);
} catch {
  payload = item.json.body ?? item.json;
}

const message = payload?.entry?.[0]?.changes?.[0]?.value?.messages?.[0];
if (!message) {
  return [{ json: { shouldProcess: false, reason: 'no_message_event', signatureValid, payload } }];
}

const messageText = message?.text?.body ?? message?.image?.caption ?? message?.document?.caption ?? '';

return [{
  json: {
    shouldProcess: true,
    signatureValid,
    phone: message.from ?? null,
    messageId: message.id ?? null,
    messageType: message.type ?? 'unknown',
    messageText,
    receivedAt: new Date().toISOString(),
    payload
  }
}];

const entrada = $('Verificar e Extrair Webhook').first().json;
let sessao = null;
let etapa = null;
let cacheBruto = null;
let produtos = [];

try {
  cacheBruto = $('Redis - Cache Produtos GET').first().json.value ?? null;
} catch {}

try {
  etapa = $('Redis - Etapa GET').first().json.value ?? null;
} catch {}

try {
  const sessionRaw = $('Redis - Sessao GET').first().json.value ?? null;
  sessao = sessionRaw ? JSON.parse(sessionRaw) : null;
} catch {
  sessao = null;
}

if (cacheBruto) {
  try {
    produtos = JSON.parse(cacheBruto);
  } catch {
    produtos = [];
  }
}

if (!produtos.length) {
  try {
    const preparados = $('Preparar Cache Produtos').first().json.produtos;
    if (Array.isArray(preparados)) {
      produtos = preparados;
    }
  } catch {}
}

const listaProdutos = produtos.length ? produtos.map((produto) => `${produto.nome} (id: ${produto.id}, sku: ${produto.sku || '-'}, un: ${produto.unidade || 'un'}, categoria: ${produto.categoria || '-'})`).join('\n') : 'Nenhum produto cadastrado.';

return [{
  json: {
    telefone: entrada.phone,
    mensagem: entrada.messageText,
    tipo_mensagem: entrada.messageType,
    produtos_cadastrados: listaProdutos,
    produtos_array: produtos,
    contexto_redis: sessao,
    etapa_redis: etapa,
    recebido_em: entrada.receivedAt
  }
}];

const contexto = $('Montar Contexto IA').first().json;
let saida = $json.output ?? $json;

if (saida && typeof saida === 'object' && saida.output && typeof saida.output === 'object') {
  saida = saida.output;
}

if (typeof saida === 'string') {
  try {
    saida = JSON.parse(saida);
  } catch (error) {
    throw new Error('Nao foi possivel converter a saida da IA em JSON: ' + error.message);
  }
}

if (!saida || typeof saida !== 'object') {
  throw new Error('A IA nao retornou um objeto valido.');
}

const contextoSessao = contexto.contexto_redis && typeof contexto.contexto_redis === 'object' ? contexto.contexto_redis : null;
const status = saida.status || 'aguardando_info';
let itens = Array.isArray(saida.itens) ? saida.itens : [];

if (status === 'confirmado' && !itens.length && Array.isArray(contextoSessao?.itens)) {
  itens = contextoSessao.itens;
}

const operacao = saida.operacao ?? contextoSessao?.operacao ?? null;
const mensagemPadrao = status === 'cancelado' ? 'Movimentacao cancelada.' : status === 'confirmado' ? 'Movimentacao confirmada e registrada.' : status === 'pendente' ? 'Confirme se deseja salvar esta movimentacao.' : 'Preciso de mais informacoes para continuar.';

const resultado = {
  status,
  mensagem_resposta: saida.mensagem_resposta || mensagemPadrao,
  operacao,
  itens: itens.map((item) => ({
    produto_id: item.produto_id ?? null,
    nome_original: item.nome_original ?? item.nome_matched ?? '',
    nome_matched: item.nome_matched ?? null,
    produto_novo: Boolean(item.produto_novo),
    quantidade: Number(item.quantidade ?? 0),
    unidade: item.unidade ?? 'un',
    fornecedor: item.fornecedor ?? null,
    numero_nfe: item.numero_nfe ?? null
  })),
  telefone: contexto.telefone,
  mensagem_original: contexto.mensagem
};

resultado.has_new_product = resultado.itens.some((item) => item.produto_novo || !item.produto_id);
resultado.session_payload = {
  status: 'pendente',
  operacao: resultado.operacao,
  itens: resultado.itens,
  mensagem_resposta: resultado.mensagem_resposta,
  telefone: resultado.telefone
};

return [{ json: resultado }];

const data = $('Normalizar Resultado IA').first().json;
const movimentacoes = data.itens.map((item) => ({
  produto_id: item.produto_id,
  tipo: data.operacao,
  quantidade: Number(item.quantidade),
  origem: 'whatsapp',
  operador: data.telefone,
  observacao: item.nome_original || null,
  numero_nfe: item.numero_nfe || null
})).filter((item) => item.produto_id && item.quantidade);

if (!movimentacoes.length) {
  throw new Error('Nenhum item confirmado para gravar.');
}

const produtoIds = [...new Set(movimentacoes.map((item) => item.produto_id))];

return [{
  json: {
    movimentacoes,
    produto_ids_csv: produtoIds.join(','),
    telefone: data.telefone,
    mensagem_resposta: data.mensagem_resposta
  }
}];

const criticalItems = $('Supabase - Buscar Itens Criticos').all().map((item) => item.json).filter((item) => item && item.produto_id);
const alertItems = $('Supabase - Buscar Alertas Hoje').all().map((item) => item.json).filter((item) => item && item.produto_id);
const existing = new Set(alertItems.map((item) => `${item.produto_id}:${item.tipo_alerta}`));
const managerPhone = process.env.INVENTORY_MANAGER_PHONE || '';
const referenceDay = new Date().toISOString().slice(0, 10);
const freshAlerts = criticalItems.filter((item) => !existing.has(`${item.produto_id}:${item.tipo_alerta}`));
const lines = freshAlerts.map((item) => `- ${item.nome}: atual ${item.quantidade} ${item.unidade || 'un'} | minimo ${item.estoque_min} ${item.unidade || 'un'} | deficit ${item.deficit} ${item.unidade || 'un'}${item.fornecedor ? ' | fornecedor ' + item.fornecedor : ''}`);

return [{
  json: {
    send_alert: Boolean(managerPhone) && freshAlerts.length > 0,
    manager_phone: managerPhone,
    manager_message: `Alerta de estoque critico\n\n${lines.join('\n')}\n\nReferencia: ${referenceDay}`,
    alertas_payload: freshAlerts.map((item) => ({
      produto_id: item.produto_id,
      tipo_alerta: item.tipo_alerta,
      destinatario: managerPhone,
      referencia_dia: referenceDay
    }))
  }
}];
